      // Compute the mask value: -C, where C is positive power of 2
      APInt Mask = -(*C2);
      // If comparing sgt with a positive constant C1, and C1 < Mask, then we can fold.
      if (ICmpInst::isSigned(IntPred) && IntPred == ICmpInst::ICMP_SGT && C1.isStrictlyPositive() && C1.ult(Mask)) {
        // New bound is: Mask - 1
        APInt NewRHS = Mask - 1;
        // If X is greater than NewRHS, then (X & Mask) will be at least Mask (if X has higher bits)
        // or 0, but in any case, since C1 < Mask, if X > NewRHS, then (X & Mask) >= Mask > C1.
        // Conversely, if X <= NewRHS, then (X & Mask) <= NewRHS & Mask = NewRHS (since Mask aligns), <= NewRHS < Mask.
        // But we need to ensure that (X & Mask) > C1 is equivalent to X > NewRHS.
        // However, note: if X > NewRHS, then the bit corresponding to Mask is set, so (X & Mask) >= Mask > C1 (since C1 < Mask).
        // If X <= NewRHS, then (X & Mask) <= NewRHS & Mask = NewRHS, and since NewRHS = Mask-1, (X & Mask) <= Mask-1.
        // But Mask-1 may still be > C1. So this fold is only safe if C1 >= Mask-1? Not exactly.
        // Actually, we require that C1 < Mask, but we want (X & Mask) > C1  <=> X > Mask-1.
        // However, if C1 < Mask, it's not sufficient. Consider: Mask=32, C1=16. Then:
        // - If X=31: (31 & -32)=0 > 16? false. X>31? false -> ok.
        // - If X=32: (32 & -32)=32 > 16? true. X>31? true -> ok.
        // - But what if X=48: (48 & -32)=32 > 16? true. X>31? true -> ok.
        // - What if X=16: (16 & -32)=0 > 16? false. X>31? false -> ok.
        // But is it always true that (X & Mask) > C1  iff X > Mask-1, when C1 < Mask?
        // No: Consider Mask=32, C1=16. Let X=31: X>31? false, and (X&Mask)=0 > 16? false -> ok.
        // Let X=32: 32>31 -> true, (32&32)=32>16 -> true -> ok.
        // But what if C1=0? Then we have (X & Mask) > 0. Is that equivalent to X > Mask-1?
        // No: X=1 -> (1 & 32)=0 > 0? false. X>31? false -> ok.
        // X=32 -> true in both -> ok.
        // But X=16 -> (16 & 32)=0 > 0? false, X>31? false -> ok.
        // However, X=33: (33 & 32)=32 > 0 -> true, X>31 -> true -> ok.
        // But what if C1=31? Then C1 < 32 -> true. Then we would fold to X>31.
        // X=31: X>31? false, (31 & 32)=0 >31? false -> ok.
        // X=32: 32>31 -> true, (32&32)=32>31 -> true -> ok.
        // X=63: 63>31 -> true, (63&32)=32>31 -> true -> ok.
        // X=64: same.
        // But X=31: still ok.
        // However, what if C1=32? Then C1 >= Mask -> skip.
        // But note: C1=31 < Mask=32 -> allowed.
        // But is (X & 32) > 31 equivalent to X > 31?
        // (X & 32) is either 0 or 32.
        // So (X & 32) > 31  <=> (X & 32) == 32  <=> X has bit 5 set.
        // X > 31: requires that X >= 32.
        // But if X has bit 5 set, X >= 32 -> so yes, X>=32 <=> X>31.
        // So (X & 32) > 31  <=> X has bit 5 set <=> X >= 32 <=> X > 31.
        // Similarly, if C1=16, then (X & 32) > 16  <=> (X & 32) != 0 <=> X has bit 5 set <=> X >= 32 <=> X > 31.
        // In fact, for any C1 in [0, 31], (X & 32) > C1  is true iff (X & 32) != 0 (because the only nonzero value is 32, which is > any C1 < 32).
        // So (X & 32) > C1 (for C1 < 32) is equivalent to (X & 32) != 0, which is equivalent to X >= 32, i.e., X > 31.
        // Therefore, for any C1 < Mask, (X & Mask) > C1  <=> (X & Mask) != 0 <=> X >= Mask <=> X > (Mask-1).
        // Therefore, we can fold icmp sgt (and X, Mask), C1  --> icmp sgt X, (Mask-1) if C1 < Mask.
        if (C1.ult(Mask)) {
          Constant *NewCmpRHS = ConstantInt::get(X->getType(), NewRHS);
          return new ICmpInst(IntPred, X, NewCmpRHS);
        }
      }
    }
